insert into public.communities(name,slug,category,short_description,description,region,tags,meeting_type,participation_type,fee_type,fee,status,thumbnail_url,next_meeting_at,capacity,current_members,is_new,is_featured) values
('대구 독립영화 모임','daegu-indie-film','영화','스크린 너머의 이야기를 함께 나누는 사람들','독립영화를 보고 깊은 이야기를 나누는 커뮤니티입니다.','교동',array['영화','문화','교동'],'regular','offline','paid',15000,'recruiting','https://images.unsplash.com/photo-1529156069898-49953e39b3ac?auto=format&fit=crop&w=900&q=80','2026-07-18 19:30+09',14,8,false,true),
('퇴근 후 북클럽','after-work-books','독서','한 달 한 권, 오래 남는 대화를 나눠요','책을 매개로 낯선 이웃과 자연스럽게 연결되는 모임입니다.','범어',array['독서','수성못','직장인'],'regular','offline','free',null,'recruiting','https://images.unsplash.com/photo-1511632765486-a01980e01a18?auto=format&fit=crop&w=900&q=80','2026-07-19 19:30+09',12,9,false,true),
('주말 사진 산책','weekend-photo-walk','사진','골목의 빛과 계절을 천천히 기록해요','도시를 걸으며 사진과 이야기를 기록합니다.','동성로',array['사진','산책','동성로'],'one-time','offline','free',null,'recruiting','https://images.unsplash.com/photo-1528605248644-14dd04022da1?auto=format&fit=crop&w=900&q=80','2026-07-20 16:00+09',16,10,false,true),
('로컬 창업 스터디','local-founders','네트워킹','작게 시작하는 동네 브랜드의 실전 모임','로컬 창업과 브랜드 경험을 나누는 네트워킹 모임입니다.','복현동',array['창업','로컬 브랜드','경북대'],'regular','offline','paid',15000,'recruiting','https://images.unsplash.com/photo-1543269865-cbf427effbad?auto=format&fit=crop&w=900&q=80','2026-07-21 19:30+09',15,7,false,true),
('한 문장 글쓰기','one-sentence','글쓰기','매일의 마음을 짧고 단단하게 쓰는 연습','매주 글을 쓰고 안전하게 감상을 나눕니다.','성서',array['글쓰기','계명대'],'regular','offline','free',null,'recruiting','https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&fit=crop&w=900&q=80','2026-07-22 19:30+09',12,8,false,false),
('재즈 깊이 듣기','deep-jazz','음악','좋은 음반과 느긋한 대화가 있는 밤','재즈 음반 한 장을 함께 깊이 듣습니다.','수성못',array['음악','재즈','수성못'],'regular','offline','free',null,'recruiting','https://images.unsplash.com/photo-1521737711867-e3b97375f902?auto=format&fit=crop&w=900&q=80','2026-07-23 20:00+09',12,6,false,false),
('일요일 러닝 크루','sunday-runners','운동','속도보다 함께 달리는 즐거움을 찾아요','앞산을 천천히 달리는 초보 친화 러닝 모임입니다.','앞산',array['운동','러닝','앞산'],'regular','offline','paid',15000,'recruiting','https://images.unsplash.com/photo-1529156069898-49953e39b3ac?auto=format&fit=crop&w=900&q=80','2026-07-24 08:00+09',18,11,false,false),
('손으로 만드는 토요일','craft-saturday','취미','도자기와 뜨개로 보내는 조용한 오후','손으로 만드는 시간을 함께 보내요.','봉산동',array['취미','공예','동성로'],'one-time','offline','free',null,'recruiting','https://images.unsplash.com/photo-1511632765486-a01980e01a18?auto=format&fit=crop&w=900&q=80','2026-07-25 14:00+09',10,6,false,false),
('작은 전시 탐험대','gallery-explorers','전시·공연','대구의 작은 전시를 함께 발견해요','골목의 전시 공간을 찾아 함께 감상합니다.','반월당',array['전시','문화','동성로'],'regular','offline','free',null,'recruiting','https://images.unsplash.com/photo-1528605248644-14dd04022da1?auto=format&fit=crop&w=900&q=80','2026-07-26 15:00+09',15,9,true,false),
('기획자의 사이드워크','sidework','스터디','아이디어를 매주 한 칸씩 현실로 옮겨요','작은 사이드 프로젝트를 함께 실행합니다.','만촌',array['스터디','기획','수성못'],'regular','offline','paid',15000,'recruiting','https://images.unsplash.com/photo-1543269865-cbf427effbad?auto=format&fit=crop&w=900&q=80','2026-07-27 19:30+09',12,7,true,false),
('초보 클라이밍 데이','climbing-day','운동','처음이어도 괜찮은 가벼운 클라이밍','처음 시작하는 사람을 위한 하루 체험입니다.','산격동',array['운동','클라이밍','경북대'],'one-time','offline','free',null,'upcoming','https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&fit=crop&w=900&q=80','2026-07-28 18:30+09',14,6,true,false),
('동네 음악 작업실','local-music-lab','음악','만들고 연주하고 서로의 소리를 응원해요','작은 음악을 만들고 서로 피드백합니다.','계명대',array['음악','작곡','계명대'],'regular','offline','free',null,'recruiting','https://images.unsplash.com/photo-1521737711867-e3b97375f902?auto=format&fit=crop&w=900&q=80','2026-07-29 19:30+09',12,8,true,false);
insert into public.schedules(community_id,community_name,title,date,start_time,end_time,location,description,capacity,status) select c.id,c.name,'7월 정기 모임 '||g::text,('2026-07-'||lpad((17+g)::text,2,'0'))::date,'19:00','21:00',c.region||' 모디 라운지','커뮤니티 정기 일정',c.capacity,'upcoming' from generate_series(1,10)g join lateral(select * from public.communities order by created_at offset g-1 limit 1)c on true;
insert into public.checklist_groups(community_id,title,display_order) select id,x.title,x.ord from public.communities c cross join(values('모임 준비',0),('모임 전',1),('모임 당일',2),('모임 이후',3))x(title,ord) where c.slug='after-work-books';
insert into public.checklist_items(group_id,title,completed) select g.id,x.title,false from public.checklist_groups g join lateral(values('첫 번째 준비 항목'),('두 번째 준비 항목'),('세 번째 준비 항목'))x(title) on true;
insert into public.community_applications(community_id,community_name,applicant_name,applied_at,introduction,motivation,status) select c.id,c.name,x.name,current_date-x.ago,x.intro,x.motive,x.status from public.communities c cross join(values('김민지',1,'책과 대화를 좋아해요.','함께 깊게 읽고 싶어요.','pending'),('박준호',2,'대구에서 직장 생활을 해요.','꾸준한 취미를 만들고 싶어요.','approved'),('이서연',3,'에세이를 좋아해요.','취향이 비슷한 이웃을 만나고 싶어요.','pending'),('최도윤',4,'새로운 관점을 즐겨요.','좋은 질문을 나누고 싶어요.','pending'),('정하늘',5,'매일 조금씩 읽어요.','읽는 습관을 이어가고 싶어요.','approved'),('한유진',6,'독립서점을 자주 찾아요.','책 이야기를 나누고 싶어요.','rejected'),('오지후',7,'인문학에 관심이 있어요.','함께 배우고 싶어요.','pending'),('윤서아',8,'소설을 좋아해요.','다양한 감상을 듣고 싶어요.','approved'))x(name,ago,intro,motive,status) where c.slug='after-work-books';
